        "imageUrl": "https://mlavgymrtxzc.i.optimole.com/cb:572_.56b/w:auto/h:auto/q:mauto/f:best/https://biolongevitylabs.com/wp-content/uploads/2025/12/bonomarlot-bone-marrow.jpg",
